async (page) => {
  const fs = require('fs');
  const path = require('path');
  const saveDir = 'D:\\fidelity\\statements';

  // Ensure directory exists
  if (!fs.existsSync(saveDir)) fs.mkdirSync(saveDir, { recursive: true });

  const years = ['2016','2017','2018','2019','2020','2021','2022','2023','2024','2025','2026'];
  const targetAccounts = ['Multiple accounts', 'ROTH IRA 107980145'];
  const downloaded = [];
  const skipped = [];

  for (const year of years) {
    // Click the filter dropdown
    await page.getByRole('button', { name: /Last|[0-9]{4}/ }).first().click();
    await page.waitForSelector('[role="menu"]');

    // Click the year
    const yearItem = page.getByRole('menuitem', { name: year });
    await yearItem.click();

    // Wait for table to reload
    await page.waitForTimeout(2000);

    // Load all results by clicking "Load more" until it's gone
    let loadMoreVisible = true;
    while (loadMoreVisible) {
      const loadMore = page.getByRole('button', { name: 'Load more results' });
      if (await loadMore.isVisible()) {
        await loadMore.click();
        await page.waitForTimeout(1500);
      } else {
        loadMoreVisible = false;
      }
    }

    // Find all rows in the statements table
    const rows = await page.$$('table tbody tr, table rowgroup tr');

    for (const row of rows) {
      // Get the account cell text
      const cells = await row.$$('td, [role="cell"]');
      if (cells.length < 2) continue;

      const descText = await cells[0].textContent();
      const accountText = await cells[1].textContent();

      // Only download for our target accounts
      const isTarget = targetAccounts.some(t => accountText.trim().includes(t));
      if (!isTarget) continue;

      // Find download button
      const downloadBtn = await row.$('button[aria-label*="download"], button:has-text("download")');
      if (!downloadBtn) continue;

      // Set up download handler
      const [download] = await Promise.all([
        page.waitForEvent('download'),
        downloadBtn.click()
      ]);

      // Build filename: account_description.pdf
      const safeName = accountText.trim().replace(/[^a-zA-Z0-9 ]/g, '').replace(/\s+/g, '_');
      const safeDesc = descText.trim().replace(/[^a-zA-Z0-9 ]/g, '').replace(/\s+/g, '_');
      const filename = `${safeName}_${safeDesc}.pdf`;
      const savePath = path.join(saveDir, filename);

      await download.saveAs(savePath);
      downloaded.push(filename);
    }
  }

  return { downloaded: downloaded.length, files: downloaded, skipped };
}

