async (page) => {
  // Helper: select a year from the filter dropdown
  const selectYear = async (year) => {
    const btn = page.locator('button').filter({ hasText: /Last \d+ months|\d{4}/ }).first();
    await btn.click();
    await page.waitForSelector('[role="menu"]', { timeout: 5000 });
    await page.getByRole('menuitem', { name: year, exact: true }).click();
    await page.waitForTimeout(2500);
  };

  // Helper: load all results
  const loadAll = async () => {
    let attempts = 0;
    while (attempts < 20) {
      const btn = page.locator('button', { hasText: 'Load more results' });
      if (await btn.isVisible().catch(() => false)) {
        await btn.click();
        await page.waitForTimeout(1500);
        attempts++;
      } else break;
    }
  };

  // Helper: get target rows (returns array of {desc, account, rowIndex})
  const getTargetRows = async () => {
    return await page.$$eval('table tr', rows =>
      rows.map((row, i) => {
        const cells = row.querySelectorAll('td');
        if (cells.length < 2) return null;
        const account = cells[1]?.textContent?.trim();
        const desc = cells[0]?.textContent?.trim();
        if (!account) return null;
        const isTarget = account.includes('Multiple accounts') || account.includes('ROTH IRA 107980145');
        if (!isTarget) return null;
        return { desc, account, rowIndex: i };
      }).filter(Boolean)
    );
  };

  const years = ['2016','2017','2018','2019','2020','2021','2022','2023','2024','2025','2026'];
  const downloaded = [];
  const saveDir = 'D:\\fidelity\\statements';

  for (const year of years) {
    await selectYear(year);
    await loadAll();

    const targetRows = await getTargetRows();
    if (targetRows.length === 0) continue;

    for (const rowInfo of targetRows) {
      // Re-query the row each time to avoid stale refs
      const rows = await page.$$('table tr');
      const row = rows[rowInfo.rowIndex];
      if (!row) continue;

      const dlBtn = await row.$('button[aria-label="download statement"]');
      if (!dlBtn) continue;

      const safeName = rowInfo.account.replace(/[^a-zA-Z0-9]/g, '_');
      const safeDesc = rowInfo.desc.replace(/[^a-zA-Z0-9]/g, '_').replace(/__+/g, '_');
      const filename = `${safeName}_${safeDesc}.pdf`;

      const [download] = await Promise.all([
        page.waitForEvent('download', { timeout: 30000 }),
        dlBtn.click()
      ]);

      await download.saveAs(`${saveDir}\\${filename}`);
      downloaded.push(filename);
    }
  }

  return { total: downloaded.length, files: downloaded };
}

