/**
 * Fidelity Statement Downloader
 * Downloads all statements for "Multiple accounts" and "ROTH IRA 107980145"
 * going back to 2016, saving them to D:\fidelity\statements
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const SAVE_DIR = 'D:\\fidelity\\statements';
const TARGET_ACCOUNTS = ['Multiple accounts', 'ROTH IRA 107980145'];
const YEARS = ['2016','2017','2018','2019','2020','2021','2022','2023','2024','2025','2026'];

async function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

async function selectYear(page, year) {
  console.log(`  Selecting year: ${year}`);
  await page.locator('#select-button').click();
  await sleep(800);
  await page.locator('#select-options-container [role="menuitem"]').filter({ hasText: new RegExp(`^${year}$`) }).click();
  await sleep(3000);
}

async function loadAllResults(page) {
  let count = 0;
  while (count < 30) {
    const btn = page.locator('button').filter({ hasText: 'Load more results' });
    if (await btn.isVisible().catch(() => false)) {
      await btn.click();
      await sleep(1500);
      count++;
    } else break;
  }
}

async function downloadYearStatements(page, year) {
  const downloaded = [];
  const errors = [];

  await selectYear(page, year);
  await loadAllResults(page);

  const rows = await page.$$('table tr');
  console.log(`  Found ${rows.length} rows for ${year}`);

  for (let i = 0; i < rows.length; i++) {
    const cells = await rows[i].$$('td');
    if (cells.length < 2) continue;

    const account = (await cells[1].textContent()).trim();
    if (!TARGET_ACCOUNTS.some(t => account.includes(t))) continue;

    const desc = (await cells[0].textContent()).trim();
    const dlBtn = await rows[i].$('button[aria-label="download statement"]');
    if (!dlBtn) continue;

    const safeName = account.replace(/[^a-zA-Z0-9]/g, '_');
    const safeDesc = desc.replace(/[^a-zA-Z0-9]/g, '_').replace(/_+/g, '_');
    const filename = `${safeName}_${safeDesc}.pdf`;
    const savePath = path.join(SAVE_DIR, filename);

    // Skip if already downloaded
    if (fs.existsSync(savePath)) {
      console.log(`  SKIP (exists): ${filename}`);
      downloaded.push(filename);
      continue;
    }

    try {
      console.log(`  Downloading: ${filename}`);
      const [dl] = await Promise.all([
        page.waitForEvent('download', { timeout: 30000 }),
        dlBtn.click()
      ]);
      await dl.saveAs(savePath);
      console.log(`  Saved: ${filename}`);
      downloaded.push(filename);
      await sleep(500);
    } catch (e) {
      console.error(`  ERROR downloading ${filename}: ${e.message}`);
      errors.push({ filename, error: e.message });
    }
  }

  return { downloaded, errors };
}

async function main() {
  // Ensure save directory exists
  fs.mkdirSync(SAVE_DIR, { recursive: true });

  console.log('Launching browser... Please log in when the browser opens.');
  const browser = await chromium.launch({ headless: false, slowMo: 100 });
  const context = await browser.newContext({ acceptDownloads: true });
  const page = await context.newPage();

  // Navigate to Fidelity statements page
  await page.goto('https://digital.fidelity.com/ftgw/digital/portfolio/documents/dochub/statement');

  // Wait for user to log in if needed
  console.log('\nWaiting for login and statements page to load...');
  await page.waitForURL('**/dochub/statement', { timeout: 120000 });
  await page.waitForSelector('#select-button', { timeout: 30000 });
  console.log('Statements page loaded. Starting downloads...\n');

  const allDownloaded = [];
  const allErrors = [];

  for (const year of YEARS) {
    console.log(`\n=== Processing year: ${year} ===`);
    try {
      const { downloaded, errors } = await downloadYearStatements(page, year);
      allDownloaded.push(...downloaded);
      allErrors.push(...errors);
      console.log(`  Year ${year}: ${downloaded.length} files`);
    } catch (e) {
      console.error(`  ERROR for year ${year}: ${e.message}`);
      allErrors.push({ year, error: e.message });
    }
  }

  // Write summary
  const summary = {
    total: allDownloaded.length,
    downloaded: allDownloaded,
    errors: allErrors,
    savedTo: SAVE_DIR
  };
  fs.writeFileSync(path.join(SAVE_DIR, '_download_summary.json'), JSON.stringify(summary, null, 2));

  console.log('\n=== DONE ===');
  console.log(`Total downloaded: ${allDownloaded.length}`);
  console.log(`Errors: ${allErrors.length}`);
  console.log(`Files saved to: ${SAVE_DIR}`);
  if (allErrors.length > 0) {
    console.log('\nErrors:');
    allErrors.forEach(e => console.log(`  ${JSON.stringify(e)}`));
  }

  await browser.close();
}

main().catch(e => {
  console.error('Fatal error:', e);
  process.exit(1);
});

