async function downloadURL(url, cookies, savePath) {
  return new Promise((resolve, reject) => {
    const urlObj = new URL(url);
    const lib = urlObj.protocol === 'https:' ? https : http;
    const cookieStr = cookies.map(c => `${c.name}=${c.value}`).join('; ');
    const options = {
      hostname: urlObj.hostname,
      path: urlObj.pathname + urlObj.search,
      headers: {
        'Cookie': cookieStr,
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
        'Referer': 'https://digital.fidelity.com/'
      }
    };
    const file = fs.createWriteStream(savePath);
    lib.get(options, (res) => {
      if (res.statusCode === 302 || res.statusCode === 301) {
        file.close();
        return downloadURL(res.headers.location, cookies, savePath).then(resolve).catch(reject);
      }
      res.pipe(file);
      file.on('finish', () => { file.close(); resolve(); });
    }).on('error', (e) => { fs.unlink(savePath, () => {}); reject(e); });
  });
}

