  for (let i = 0; i < rows.length; i++) {
    const cells = await rows[i].$$('td');
    if (cells.length < 2) continue;
    const account = (await cells[1].textContent()).trim();
    if (!TARGET_ACCOUNTS.some(t => account.includes(t))) continue;
    const desc = (await cells[0].textContent()).trim();
    const dlBtn = await rows[i].$('button[aria-label="download statement"]');
    if (!dlBtn) continue;

    const filename = account.replace(/[^a-zA-Z0-9]/g,'_') + '_' + desc.replace(/[^a-zA-Z0-9]/g,'_').replace(/_+/g,'_') + '.pdf';
    const savePath = path.join(SAVE_DIR, filename);
    if (fs.existsSync(savePath)) { console.log(`  SKIP: ${filename}`); downloaded.push(filename); continue; }

    try {
      console.log(`  Downloading: ${filename}`);

      // Click the download button to open the dropdown
      await dlBtn.click();
      await sleep(500);

      // Wait for the "Download as PDF" menu item and click it
      // It opens a new tab with the PDF URL
      const [newPage] = await Promise.all([
        context.waitForEvent('page', { timeout: 15000 }),
        page.getByRole('menuitem', { name: 'Download as PDF' }).click()
      ]);

      // Get the URL from the new tab
      await newPage.waitForLoadState('domcontentloaded', { timeout: 15000 }).catch(() => {});
      const pdfUrl = newPage.url();
      console.log(`  PDF URL: ${pdfUrl}`);
      await newPage.close();

      // Download the PDF using cookies from the session
      const cookies = await context.cookies();
      await downloadURL(pdfUrl, cookies, savePath);
      console.log(`  SAVED: ${filename}`);
      downloaded.push(filename);
      await sleep(300);
    } catch(e) {
      console.error(`  ERROR: ${filename} - ${e.message}`);
      errors.push({ filename, error: e.message });
    }
  }
  return { downloaded, errors };
}

async function main() {
  fs.mkdirSync(SAVE_DIR, { recursive: true });
  console.log('Launching browser...');
  const browser = await chromium.launch({ headless: false, slowMo: 50 });
  const context = await browser.newContext({ acceptDownloads: true });
  const page = await context.newPage();

  console.log('Navigating to Fidelity...');
  await page.goto('https://digital.fidelity.com/ftgw/digital/portfolio/documents/dochub/statement');
  console.log('Please log in. Waiting for statements page...');
  await page.waitForURL('**/dochub/statement', { timeout: 120000 });
  await page.waitForSelector('button.green-background, #select-button', { timeout: 30000 });
  await sleep(2000);
  console.log('Ready! Starting downloads...\n');

  const allDownloaded = [], allErrors = [];
  for (const year of YEARS) {
    console.log(`\n=== Year: ${year} ===`);
    try {
      const { downloaded, errors } = await downloadYear(page, context, year);
      allDownloaded.push(...downloaded);
      allErrors.push(...errors);
      console.log(`  Year ${year}: ${downloaded.length} downloaded, ${errors.length} errors`);
    } catch(e) {
      console.error(`  YEAR ERROR ${year}: ${e.message}`);
      allErrors.push({ year, error: e.message });
    }
  }

  const summary = { total: allDownloaded.length, downloaded: allDownloaded, errors: allErrors };
  fs.writeFileSync(path.join(SAVE_DIR, '_summary.json'), JSON.stringify(summary, null, 2));
  console.log(`\n=== DONE! Total: ${allDownloaded.length} files. Errors: ${allErrors.length} ===`);
  await browser.close();
}

main().catch(e => { console.error('FATAL:', e.message); process.exit(1); });
